\begin{aligned}
a < b &\quad \text{means } a \text{ is less than } b \\
a > b &\quad \text{means } a \text{ is greater than } b \\
a \leq b &\quad \text{means } a \text{ is less than or equal to } b \\
a \geq b &\quad \text{means } a \text{ is greater than or equal to } b
\end{aligned}

\begin{aligned}
m > 0 &\Rightarrow \text{line rises left to right (positive slope)} \\
m < 0 &\Rightarrow \text{line falls left to right (negative slope)} \\
m = 0 &\Rightarrow \text{horizontal line} \\
\text{Undefined slope} &\Rightarrow \text{vertical line}
\end{aligned}
